2315 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2316 |     function applyLocalPatch(content, ops) {
2317 |         let lines = content.split('\n');
2318 |         let logs = [];
2319 |         let success = true;
2320 | 
2321 |         if (typeof ops === 'string') {
2322 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2323 |         }
2324 | 
2325 |         ops.forEach(op => {
2326 |             if (op.action === 'comment') return;
2327 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2328 |             
2329 |             if (op.action === 'replace_block') {
2330 |                 // Strategy 1: Exact String Match (Fastest)
2331 |                 const currentStr = lines.join('\n');
2332 |                 if (currentStr.includes(op.find_block)) {
2333 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2334 |                     logs.push('Exact match applied');
2335 |                     return;
2336 |                 }
2337 | 
2338 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2339 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2340 |                 if (searchLines.length === 0) return;
2341 | 
2342 |                 let matchStart = -1;
2343 |                 let matchEnd = -1;
2344 | 
2345 |                 // Scan file lines
2346 |                 for (let i = 0; i < lines.length; i++) {
2347 |                     // If first line matches (ignoring whitespace)
2348 |                     if (lines[i].trim() === searchLines[0]) {
2349 |                         // Check subsequent lines
2350 |                         let allMatch = true;
2351 |                         let fileOffset = 0;
2352 |                         let searchOffset = 1;
2353 |                         
2354 |                         while (searchOffset < searchLines.length) {
2355 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2356 |                             const nextFile = lines[i + fileOffset + 1].trim();
2357 |                             // Skip empty lines in file if they aren't in search block
2358 |                             if (nextFile === '') {
2359 |                                 fileOffset++;
2360 |                                 continue;
2361 |                             }
2362 |                             if (nextFile !== searchLines[searchOffset]) {
2363 |                                 allMatch = false;
2364 |                                 break;
2365 |                             }
2366 |                             fileOffset++;
2367 |                             searchOffset++;
2368 |                         }
2369 | 
2370 |                         if (allMatch) {
2371 |                             matchStart = i;
2372 |                             matchEnd = i + fileOffset;
2373 |                             break;
2374 |                         }
2375 |                     }
2376 |                 }
2377 | 
2378 |                 if (matchStart !== -1) {
2379 |                     // Replace the range of lines
2380 |                     const replacement = op.replace_with.split('\n');
2381 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2382 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2383 |                 } else {
2384 |                     success = false;
2385 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2386 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2387 |                 }
2388 |             }
2389 |         });
2390 |         return { content: lines.join('\n'), success, logs };
2391 |     }
