5314 |     function formatBytes(bytes) {
5315 |         if (!bytes) return '0 B';
5316 |         const k = 1024;
5317 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5318 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5319 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5320 |     }
