5322 |     function timeAgo(dateString) {
5323 |         const date = new Date(dateString);
5324 |         const now = new Date();
5325 |         const seconds = Math.floor((now - date) / 1000);
5326 |         if (seconds < 10) return 'just now';
5327 |         if (seconds < 60) return seconds + 's ago';
5328 |         const minutes = Math.floor(seconds / 60);
5329 |         if (minutes < 60) return minutes + 'm ago';
5330 |         const hours = Math.floor(minutes / 60);
5331 |         if (hours < 24) return hours + 'h ago';
5332 |         return date.toLocaleDateString();
5333 |     }
