8057 |     function extractTableNames(sql) {
8058 |         if (!sql) return [];
8059 |         const tables = [];
8060 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8061 |         
8062 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8063 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8064 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8065 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8066 | 
8067 |         let match;
8068 |         while ((match = fromRegex.exec(sql)) !== null) {
8069 |             const name = match[1];
8070 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8071 |                 tables.push(name);
8072 |             }
8073 |         }
8074 |         
8075 |         while ((match = metaRegex.exec(sql)) !== null) {
8076 |             const name = match[1];
8077 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8078 |                 tables.push(name);
8079 |             }
8080 |         }
8081 | 
8082 |         return tables;
8083 |     }
8084 | 
8085 |     function convertToCSV(resultObj) {
8086 |         const data = resultObj.data || [];
8087 |         if (!data.length) return '';
8088 |         
8089 |         const tables = extractTableNames(resultObj.sql);
8090 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8091 | 
8092 |         const headers = Object.keys(data[0]);
8093 |         const rows = data.map(row => 
8094 |             headers.map(header => {
8095 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8096 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8097 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8098 |             }).join(',')
8099 |         );
8100 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8101 |     }
